/**
 * 面板日期相关变化
 */

import moment from 'moment';
import { useConstant } from '@universe-design/react-utilities';
import React from 'react';
import type { MODE } from '../interface';
import { getNext, getPrev } from '../panels/base/utils';
import { getStartOfPanel } from '../utils/ui';

type PickerValues = [moment.Moment, moment.Moment];

export default function ({
  value,
  defaultPickerValue: defaultPickerValueProp = [],
  panelIntervalLimited,
  mode,
}: {
  value: [moment.Moment?, moment.Moment?];
  defaultPickerValue?: [moment.Moment?, moment.Moment?];
  panelIntervalLimited: boolean;
  mode: MODE;
}) {
  const updatePickerValuesByStart = React.useCallback(
    (current: PickerValues, start: moment.Moment): PickerValues => {
      if (panelIntervalLimited) {
        return [start, getNext(start, mode)];
      }

      const [, end] = current;
      if (getStartOfPanel(start, mode).isBefore(getStartOfPanel(end, mode))) {
        return [start, end];
      }
      return [start, getNext(start, mode)];
    },
    [mode, panelIntervalLimited],
  );

  const updatePickerValuesByEnd = React.useCallback(
    (current: PickerValues, end: moment.Moment): PickerValues => {
      if (panelIntervalLimited) {
        return [getPrev(end, mode), end];
      }

      const [start] = current;

      // 如果左面板时间大于或等于右面板时间，调整右面板
      if (!getStartOfPanel(end, mode).isAfter(getStartOfPanel(start, mode))) {
        return [getPrev(end, mode), end];
      } else {
        return [start, end];
      }
    },
    [mode, panelIntervalLimited],
  );

  /**
   * 对 defaultPickerValue 做格式化
   *
   * 在面板是否联动时，defaultPickerValue 的含义是有区别的：
   * 1. 不联动： defaultPickerValue[1] 表示右面板时间
   * 2. 联动：defaultPickerValue[1] 表示左面板时间
   *
   * 这里需要抹平差异，归到 1
   */
  const defaultPickerValue = React.useMemo(() => {
    if (!defaultPickerValueProp?.length) {
      return [];
    }

    const [start, _end] = defaultPickerValueProp;
    let end = _end?.clone();

    // 如果有 start, 没有 end
    if (!end && start) {
      end = getNext(start, mode);
    }

    if (end && panelIntervalLimited) {
      end = getNext(end, mode);
    }
    return [start, end];
  }, [defaultPickerValueProp, mode, panelIntervalLimited]);

  /**
   *  面板的初始时间：
   *  是否从 value 或 defaultPickerValue 获取面板值
   *  不应该把 defaultPickerValue 理解为 面板默认时间
   *  而是当 value 为 null 时，面板显示的日期
   */
  const initialPickerValue = useConstant(() => {
    // 优先使用 value, 其次使用用户传入的 defaultPickerValue, 最后使用当前时间
    const start = value[0] ?? defaultPickerValue[0] ?? moment();
    const end = value[1] ?? defaultPickerValue[1] ?? getNext(start, mode);

    return updatePickerValuesByStart([start, end], start);
  });

  // States
  const [pickerValues, setPickerValues] = React.useState<PickerValues>(initialPickerValue);

  const [startPickerValue, endPickerValue] = pickerValues;

  // set start panel picker value
  const setStartPickerValue = React.useCallback(
    (v: moment.Moment) => {
      setPickerValues(updatePickerValuesByStart(pickerValues, v));
    },
    [updatePickerValuesByStart, pickerValues],
  );

  // set end panel picker value
  const setEndPickerValue = React.useCallback(
    (v: moment.Moment) => {
      setPickerValues(updatePickerValuesByEnd(pickerValues, v));
    },
    [updatePickerValuesByEnd, pickerValues],
  );

  // set end panel picker value
  return {
    startPickerValue,
    endPickerValue,
    setStartPickerValue,
    setEndPickerValue,
    defaultPickerValue,
    /**
     * 为了 API 兼容
     */
    setPickerValue: setStartPickerValue,
    pickerValue: startPickerValue,
  };
}
